scwin.sbm_save_submitdone = async function (e) {
  if (e.responseJSON.resultDataSet[0].Code != -1) {
    await $c.win.alert($p, $c.data.getMessage($p, MSG_CM_INF_001)); // 성공적으로 저장하였습니다
    ds_work_unit.reform();
    ds_work_unit_list.reform();
    ds_com_unit_list.reform();
  } else {
    if (scwin.cvNNew) {
      scwin.f_Cancel();
      scwin.f_Create();
    }
  }
};
